    {
      "keystrokes": "cd /app && wc -l main_obj.txt sphere_obj.txt plane_obj.txt sky_obj.txt write_image_obj.txt\n",
      "duration": 0.2
    },
    {
      "keystrokes": "cd /app && python3 - <<'PY'\nfrom pathlib import Path\nimport struct\ndata=Path('mystery').read_bytes()\nfor i in range(0x485a40,0x485c00,16):\n    off=i-0x400000\n    row=data[off:off+16]\n    fs=[]\n    for j in range(0,len(row)-3,4):\n        f=struct.unpack('<f',row[j:j+4])[0]\n        if 1e-6<abs(f)<1e3:\n            fs.append(f'+{j}={f:.7g}')\n    ascii=''.join(chr(x) if 32<=x<127 else '.' for x in row)\n    print(f'{i:08x}: '+' '.join(f'{x:02x}' for x in row)+' | '+ascii+' | '+' '.join(fs))\nPY\n",
      "duration": 1.0
    },
    {
      "keystrokes": "cd /app && sed -n '1,90p' main_obj.txt\n",
      "duration": 0.2
    },
